import React from 'react';
import { useRouter } from 'next/router';
import { useJournal } from '../../../hooks/useJournal';
import { JournalSidebar } from '../../../components/journal/JournalSidebar';

const JournalPage = () => {
  const router = useRouter();
  const { id } = router.query;
  const { getEntry, updateEntry } = useJournal();
  const entry = getEntry(id as string);

  if (!entry) {
    return <div>Loading...</div>;
  }

  const handleTitleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    updateEntry(id as string, { title: e.target.value });
  };

  return (
    <div className="flex">
      <JournalSidebar selectedEntryId={id as string} onSelect={(id) => router.push(`/journal/${id}`)} />
      <div className="flex-1 p-4">
        <input
          type="text"
          value={entry.title}
          onChange={handleTitleChange}
          className="w-full text-2xl font-bold mb-4"
        />
        {/* Add more fields and editor here */}
      </div>
    </div>
  );
};

export default JournalPage; 